use std::collections::HashMap;

fn fruit_basket(basket: &mut HashMap<String, u32>, fruit_list: Vec<&str>) {
    for fruit in fruit_list {
        let count = basket.entry(fruit.to_string()).or_insert(0);
        *count += 1;
    }
}

fn main() {
    let mut basket = HashMap::new();
    basket.insert(String::from("banana"), 2);

    let fruit_list = vec!["apple", "banana", "mango", "apple", "banana"];
    fruit_basket(&mut basket, fruit_list);

    println!("Basket: {:?}", basket);
    assert_eq!(*basket.get("banana").unwrap(), 4);
    assert_eq!(*basket.get("apple").unwrap(), 2);
    assert_eq!(*basket.get("mango").unwrap(), 1);
}
